<?php

session_start();
require_once 'config/db.php';
require_once 'config/mail_helper.php';
require_once 'config/sms_helper.php';

if (!isset($_SESSION['user_id'])) {
    header('Location: auth/login.php');
    exit();
}

if (empty($_SESSION['cart'])) {
    header('Location: cart.php');
    exit();
}

$userId = $_SESSION['user_id'];
$error = '';

$stmt = $conn->prepare("SELECT username, email, phone, address FROM users WHERE id = ?");
$stmt->bind_param("i", $userId);
$stmt->execute();
$user = $stmt->get_result()->fetch_assoc();
$stmt->close();

$total = 0;
foreach ($_SESSION['cart'] as $item) {
    $total += $item['price'] * $item['quantity'];
}

// Apply GST (5% average) 
$gstRate = 5;
$gstAmount = round($total * $gstRate / 100, 2);

// Apply coupon
$coupon = $_SESSION['coupon'] ?? null;
$discount = $coupon ? floatval($coupon['discount']) : 0;
$grandTotal = $total + $gstAmount - $discount;

if ($_SERVER['REQUEST_METHOD'] === 'POST') {
    $billingName    = trim($_POST['billing_name']);
    $billingEmail   = trim($_POST['billing_email']);
    $billingPhone   = trim($_POST['billing_phone']);
    $billingAddress = trim($_POST['billing_address']);
    $paymentMethod  = $_POST['payment_method'];
    $paymentId      = $_POST['payment_id'];

    if (empty($billingName) || empty($billingEmail) || empty($billingPhone) || empty($billingAddress)) {
        $error = "Please fill all billing details.";
    } elseif (empty($paymentId)) {
        $error = "Payment verification failed. Please try again.";
    } else {
        $stmt = $conn->prepare("INSERT INTO orders
        (user_id, total_amount, billing_name, billing_email, billing_phone, billing_address, payment_method)
        VALUES (?, ?, ?, ?, ?, ?, ?)");
        $stmt->bind_param("idsssss", $userId, $total, $billingName, $billingEmail, $billingPhone, $billingAddress, $paymentMethod);

        if ($stmt->execute()) {
            $orderId = $conn->insert_id;
            $stmtItem = $conn->prepare("INSERT INTO order_items (order_id, product_id, quantity, price) VALUES (?, ?, ?, ?)");
            $orderItems = [];
            foreach ($_SESSION['cart'] as $productId => $item) {
                $stmtItem->bind_param("iiid", $orderId, $productId, $item['quantity'], $item['price']);
                $stmtItem->execute();
                $orderItems[] = array_merge($item, ['product_id' => $productId]);
            }

            // Fetch product names for email
            $orderDetailsForEmail = array(
                'items' => [],
                'total' => $total,
                'address' => $billingAddress,
                'phone' => $billingPhone,
                'payment_method' => $paymentMethod,
                'estimated_delivery' => '2-3 business days',
                'order_link' => 'http://' . $_SERVER['HTTP_HOST'] . '/order_details.php?id=' . $orderId
            );

            foreach ($orderItems as $item) {
                $stmtProduct = $conn->prepare("SELECT name FROM products WHERE id = ?");
                $stmtProduct->bind_param("i", $item['product_id']);
                $stmtProduct->execute();
                $productResult = $stmtProduct->get_result()->fetch_assoc();
                $stmtProduct->close();

                $orderDetailsForEmail['items'][] = array(
                    'name' => $productResult['name'] ?? 'Product',
                    'quantity' => $item['quantity'],
                    'price' => $item['price']
                );
            }

            // Send order confirmation email
            sendOrderConfirmationEmail($billingEmail, $billingName, $orderId, $orderDetailsForEmail);

            // Send order confirmation SMS
            sendOrderConfirmationSMS($billingPhone, $billingName, $orderId, $orderDetailsForEmail);

            $_SESSION['cart'] = [];
            header("Location: payment/success.php?payment_id=" . urlencode($paymentId));
            exit();
        } else {
            $error = "Failed to place order.";
        }
    }
}

