<script>
var currentMethod = 'upi';

function selectPayment(method, box) {
    // Deactivate all boxes & hide panels
    document.querySelectorAll('.payment-box').forEach(b => b.classList.remove('active'));
    document.querySelectorAll('.detail-panel').forEach(p => p.classList.remove('show'));

    // Activate selected
    box.classList.add('active');
    var panel = document.getElementById('panel_' + method);
    if (panel) panel.classList.add('show');

    // Check the radio
    var radio = document.getElementById('pm_' + method);
    if (radio) radio.checked = true;

    currentMethod = method;

    // Update button
    var btn = document.getElementById('pay-btn');
    if (method === 'cod') {
        btn.textContent = 'Place Order (Cash on Delivery)';
        btn.classList.replace('btn-success', 'btn-warning');
        btn.classList.add('text-dark');
    } else {
        btn.textContent = 'Pay ₹<?php echo number_format($total, 2); ?>';
        btn.classList.remove('btn-warning', 'text-dark');
        btn.classList.add('btn-success');
        if (!btn.classList.contains('btn-success')) btn.className += ' btn-success';
    }
}

// Card number formatting
var cardInput = document.getElementById('card_number');
if (cardInput) {
    cardInput.addEventListener('input', function() {
        var v = this.value.replace(/\D/g, '').substring(0, 16);
        this.value = v.match(/.{1,4}/g)?.join(' ') || v;
    });
}

// Expiry formatting
var expiryInput = document.getElementById('card_expiry');
if (expiryInput) {
    expiryInput.addEventListener('input', function() {
        var v = this.value.replace(/\D/g, '').substring(0, 4);
        if (v.length >= 2) v = v.substring(0,2) + '/' + v.substring(2);
        this.value = v;
    });
}

// IFSC uppercase
var ifscInput = document.getElementById('bank_ifsc');
if (ifscInput) {
    ifscInput.addEventListener('input', function() {
        this.value = this.value.toUpperCase();
    });
}

document.getElementById('pay-btn').onclick = function(e) {
    e.preventDefault();

    // Validate payment details per method
    if (currentMethod === 'upi') {
        // QR code payment - no fields to validate, user scans and pays externally
    } else if (currentMethod === 'card') {
        var cn = document.getElementById('card_number').value.replace(/\s/g,'');
        var exp = document.getElementById('card_expiry').value.trim();
        var cvv = document.getElementById('card_cvv').value.trim();
        var cname = document.getElementById('card_name').value.trim();
        if (!cn || !exp || !cvv || !cname) { alert('Please fill all card details.'); return; }
        if (cn.length < 16) { alert('Please enter a valid 16-digit card number.'); return; }
        if (cvv.length < 3) { alert('Please enter a valid CVV.'); return; }
    } else if (currentMethod === 'netbanking') {
        var bank = document.getElementById('bank_name').value;
        var acc = document.getElementById('bank_account').value.trim();
        var ifsc = document.getElementById('bank_ifsc').value.trim();
        var pwd = document.getElementById('bank_password').value.trim();
        if (!bank) { alert('Please select your bank.'); return; }
        if (!acc) { alert('Please enter your account number.'); return; }
        if (!ifsc || ifsc.length < 11) { alert('Please enter a valid IFSC code (11 characters).'); return; }
        if (!pwd) { alert('Please enter your net banking password.'); return; }
    }
    // COD needs no extra validation

    var btn = document.getElementById('pay-btn');
    btn.disabled = true;
    btn.innerHTML = '<span class="spinner-border spinner-border-sm me-2"></span>' +
        (currentMethod === 'cod' ? 'Placing Order...' : 'Processing Payment...');

    setTimeout(function() {
        var dummyId = (currentMethod === 'cod' ? 'COD_' : 'DUMMY_PAY_') +
            Date.now() + '_' + Math.random().toString(36).substr(2,9).toUpperCase();
        document.getElementById('payment_id').value = dummyId;
        btn.innerHTML = '✔ ' + (currentMethod === 'cod' ? 'Order Placed!' : 'Payment Successful!');
        document.getElementById('paymentForm').submit();
    }, 2000);
};
</script>

